import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [messages, setMessages] = useState([]);

  const [tab, setTab] = useState('users');
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('all');

  // ================= FETCH =================
  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data || []));
    API.get('/admin/posts').then(res => setPosts(res.data || []));
    API.get('/admin/comments').then(res => setComments(res.data || []));
    API.get('/admin/messages').then(res => setMessages(res.data || []));
  }, []);

  // ================= ACTIONS =================
  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(prev => prev.map(u => (u._id === id ? data.user : u)));
  };

  const removePost = async (id) => {
    if (!window.confirm("Delete this post?")) return;
    await API.delete(`/posts/${id}`);
    setPosts(prev => prev.filter(p => p._id !== id));
  };

  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(prev => prev.filter(c => c._id !== id));
  };

  const markAsRead = async (id) => {
    await API.put(`/admin/messages/${id}/read`);
    setMessages(prev =>
      prev.map(m =>
        m._id === id ? { ...m, status: 'read', read: true } : m
      )
    );
  };

  const deleteMessage = async (id) => {
    await API.delete(`/admin/messages/${id}`);
    setMessages(prev => prev.filter(m => m._id !== id));
  };

  // ================= HELPERS =================
  const getMessageStatus = (m) =>
    (m.status === 'read' || m.read || m.isRead) ? 'READ' : 'NEW';

  const isMessageRead = (m) =>
    (m.status === 'read' || m.read || m.isRead);

  // ================= FILTER SYSTEM =================
  const filteredData = () => {
    const keyword = search.toLowerCase();

    let dataMap = { users, posts, comments, messages };
    let data = dataMap[tab];

    // 🔍 SEARCH
    data = data.filter(item =>
      JSON.stringify(item).toLowerCase().includes(keyword)
    );

    // 🎯 FILTER PER TAB
    if (tab === 'users') {
      if (filter === 'active') data = data.filter(u => u.status === 'active');
      if (filter === 'inactive') data = data.filter(u => u.status !== 'active');
    }

    if (tab === 'posts') {
      if (filter === 'with-author') data = data.filter(p => p.author?.name);
      if (filter === 'no-author') data = data.filter(p => !p.author?.name);
    }

    if (tab === 'comments') {
      if (filter === 'with-text') data = data.filter(c => c.body);
      if (filter === 'empty') data = data.filter(c => !c.body);
    }

    if (tab === 'messages') {
      if (filter === 'read') data = data.filter(m => getMessageStatus(m) === 'READ');
      if (filter === 'unread') data = data.filter(m => getMessageStatus(m) === 'NEW');
    }

    return data;
  };

  // ================= COLORS (PINK + GREEN THEME) =================
  const colors = {
    pinkBg: '#fdecef',
    pinkCard: '#fbd5e0',
    green: '#0c4b34',
    greenLight: '#1f7a5c',
    white: '#ffffff',
    border: '#e8a0b5'
  };

  // ================= STYLES =================
  const styles = {
    page: {
      background: colors.pinkBg,
      minHeight: '100vh',
      padding: '40px'
    },
    container: {
      maxWidth: '1150px',
      margin: 'auto',
      background: colors.pinkCard,
      padding: '30px',
      borderRadius: '25px',
      boxShadow: '0 10px 25px rgba(0,0,0,0.08)'
    },
    header: {
      textAlign: 'center',
      fontSize: '30px',
      fontWeight: '800',
      color: colors.green,
      marginBottom: '20px'
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '10px',
      marginBottom: '15px'
    },
    tab: {
      padding: '10px 18px',
      borderRadius: '20px',
      border: `2px solid ${colors.green}`,
      background: colors.white,
      cursor: 'pointer',
      fontWeight: '600'
    },
    activeTab: {
      background: colors.green,
      color: colors.white
    },
    filterBar: {
      display: 'flex',
      gap: '10px',
      marginBottom: '15px'
    },
    search: {
      flex: 1,
      padding: '10px',
      borderRadius: '10px',
      border: `1px solid ${colors.border}`
    },
    select: {
      padding: '10px',
      borderRadius: '10px',
      border: `1px solid ${colors.border}`
    },
    tableWrapper: {
      maxHeight: '450px',
      overflowY: 'auto',
      borderRadius: '15px',
      border: `2px solid ${colors.green}`
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse'
    },
    th: {
      position: 'sticky',
      top: 0,
      background: colors.green,
      color: colors.white,
      padding: '12px',
      textAlign: 'left'
    },
    td: {
      padding: '12px',
      borderBottom: `1px solid ${colors.border}`,
      color: colors.green,
      fontWeight: '600'
    },
    btn: {
      padding: '6px 12px',
      borderRadius: '10px',
      border: 'none',
      cursor: 'pointer',
      marginRight: '5px',
      fontWeight: '600'
    },
    badge: (status) => ({
      padding: '5px 10px',
      borderRadius: '10px',
      fontSize: '12px',
      color: '#fff',
      background: status === 'READ' ? colors.greenLight : '#ff8fab'
    })
  };

  // ================= FILTER OPTIONS =================
  const options = {
    users: [
      { value: 'all', label: 'All Users' },
      { value: 'active', label: 'Active' },
      { value: 'inactive', label: 'Inactive' }
    ],
    posts: [
      { value: 'all', label: 'All Posts' },
      { value: 'with-author', label: 'With Author' },
      { value: 'no-author', label: 'No Author' }
    ],
    comments: [
      { value: 'all', label: 'All Comments' },
      { value: 'with-text', label: 'With Text' },
      { value: 'empty', label: 'Empty' }
    ],
    messages: [
      { value: 'all', label: 'All Messages' },
      { value: 'read', label: 'Read' },
      { value: 'unread', label: 'Unread' }
    ]
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>

        <div style={styles.header}>Admin Dashboard</div>

        {/* ================= TABS ================= */}
        <div style={styles.tabs}>
          {['users', 'posts', 'comments', 'messages'].map(t => (
            <button
              key={t}
              onClick={() => {
                setTab(t);
                setSearch('');
                setFilter('all');
              }}
              style={{
                ...styles.tab,
                ...(tab === t ? styles.activeTab : {})
              }}
            >
              {t.toUpperCase()}
            </button>
          ))}
        </div>

        {/* ================= FILTER BAR ================= */}
        <div style={styles.filterBar}>
          <input
            style={styles.search}
            placeholder={`Search ${tab}...`}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />

          <select
            style={styles.select}
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
          >
            {options[tab].map(opt => (
              <option key={opt.value} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
        </div>

        {/* ================= TABLE ================= */}
        <div style={styles.tableWrapper}>
          <table style={styles.table}>
            <thead>
              <tr>
                {tab === 'users' && (
                  <>
                    <th style={styles.th}>Name</th>
                    <th style={styles.th}>Email</th>
                    <th style={styles.th}>Status</th>
                    <th style={styles.th}>Action</th>
                  </>
                )}

                {tab === 'posts' && (
                  <>
                    <th style={styles.th}>Title</th>
                    <th style={styles.th}>Author</th>
                    <th style={styles.th}>Action</th>
                  </>
                )}

                {tab === 'comments' && (
                  <>
                    <th style={styles.th}>Author</th>
                    <th style={styles.th}>Comment</th>
                    <th style={styles.th}>Action</th>
                  </>
                )}

                {tab === 'messages' && (
                  <>
                    <th style={styles.th}>Name</th>
                    <th style={styles.th}>Email</th>
                    <th style={styles.th}>Message</th>
                    <th style={styles.th}>Status</th>
                    <th style={styles.th}>Action</th>
                  </>
                )}
              </tr>
            </thead>

            <tbody>
              {/* USERS */}
              {tab === 'users' && filteredData().map(u => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status?.toUpperCase()}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.btn, background: colors.green, color: '#fff' }}
                      onClick={() => toggleStatus(u._id)}
                    >
                      Toggle
                    </button>
                  </td>
                </tr>
              ))}

              {/* POSTS */}
              {tab === 'posts' && filteredData().map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.author?.name}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.btn, background: '#1f7a5c', color: '#fff' }}
                      onClick={() => navigate(`/posts/${p._id}`)}
                    >
                      View
                    </button>
                    <button
                      style={{ ...styles.btn, background: '#d62828', color: '#fff' }}
                      onClick={() => removePost(p._id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}

              {/* COMMENTS */}
              {tab === 'comments' && filteredData().map(c => (
                <tr key={c._id}>
                  <td style={styles.td}>{c.author?.name}</td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.btn, background: '#d62828', color: '#fff' }}
                      onClick={() => deleteComment(c._id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}

              {/* MESSAGES */}
              {tab === 'messages' && filteredData().map(m => {
                const status = getMessageStatus(m);

                return (
                  <tr
                    key={m._id}
                    style={{ background: !isMessageRead(m) ? '#fff6f8' : 'transparent' }}
                  >
                    <td style={styles.td}>{m.name}</td>
                    <td style={styles.td}>{m.email}</td>
                    <td style={styles.td}>{m.body || m.message}</td>
                    <td style={styles.td}>
                      <span style={styles.badge(status)}>{status}</span>
                    </td>
                    <td style={styles.td}>
                      {!isMessageRead(m) && (
                        <button
                          style={{ ...styles.btn, background: colors.greenLight, color: '#fff' }}
                          onClick={() => markAsRead(m._id)}
                        >
                          Mark Read
                        </button>
                      )}
                      <button
                        style={{ ...styles.btn, background: '#d62828', color: '#fff' }}
                        onClick={() => deleteMessage(m._id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

      </div>
    </div>
  );
};

export default AdminPage;
